/**
 * @author 纷享-刘喆斌
 * @codeName 【集成】租户新建后同步至客户公海
 * @description 1
 * @createTime 2026-02-04
 * @bindingObjectLabel --
 * @bindingObjectApiName NONE
 * @函数需求编号
 */

// ============================== 以下为【同步后飞书推送】新增 ==============================
import javax.crypto.Mac
import javax.crypto.spec.SecretKeySpec
import java.nio.charset.StandardCharsets
import org.apache.commons.codec.binary.Base64
// ============================== 新增 import 结束 ==============================

/**
 * 集成流同步前/中/后函数
 * 需要处理那个步骤,只需要填写对应函数方法
 *
 * @type classes
 * @namespace erpdss-class
 * @returntype
 */
class ERPIntazwmd implements IntegrationStreamSyncPlugin {

    // ---------- 【同步后飞书推送】新增方法（卡片：新认证租户通知，适用对象 tenant__c）----------
    private static final String FEISHU_CARD_NAME = "新认证租户通知"
    private static final String FEISHU_ROW_OBJECT_API = "tenant__c"
    //private static final String FEISHU_SIGN_SECRET = "4Rht1ICA9tlKWXeqb3kb7g"
    private static final String FEISHU_SIGN_SECRET = "RbjtJN1YmdNRUVbhMiVrRc"

    /** 按「新认证租户通知」在 CRM 中配置的变量字段查 tenant__c 数据，组装正文后 POST（Webhook：全局变量 var_casa9__g） */
    private void pushFeishuMessageCard(String tenantDataId) {
        if (!tenantDataId) {
            return
        }
        def (Boolean errCard, QueryResult cardQr, String cardMsg) = Fx.object.find("feishu_message_card__c",
                FQLAttribute.builder()
                        .columns(["_id", "name", "field_8yXhs__c", "card_title__c", "theme_color__c"])
                        .queryTemplate(QueryTemplate.AND(["name": QueryOperator.EQ(FEISHU_CARD_NAME)]))
                        .build(),
                SelectAttribute.builder().build())
        if (errCard) {
            log.error("飞书卡片配置查询失败：" + cardMsg)
            return
        }
        List cardList = cardQr.dataList as List
        if (!cardList) {
            return
        }
        def asCellText = { Object v ->
            if (v == null) return ""
            if (v instanceof String) return (v as String).trim()
            if (v instanceof List) {
                List parts = []
                (v as List).each { it ->
                    if (it instanceof Map) {
                        String p = (it as Map)["label"] as String
                        if (p) parts.add(p)
                    } else if (it != null) {
                        String s = (it as String)?.trim()
                        if (s) parts.add(s)
                    }
                }
                return parts.join(", ")
            }
            if (v instanceof Map) {
                return (((v as Map)["label"]) ?: "") as String
            }
            return (v as String) ?: ""
        }
        def displayFromRow = { Map row, String fieldAPI ->
            if (!fieldAPI) return ""
            String s = asCellText(row[fieldAPI + "__r"])
            if (s) return s
            return asCellText(row[fieldAPI])
        }
        cardList.each { e ->
            Map map = e as Map
            def cardCfgId = map["_id"]
            def (Boolean perr, QueryResult pQueryResult, String perrorMessage) = Fx.object.find("message_card_variable__c",
                    FQLAttribute.builder()
                            .columns(["placeholder__c", "single_line_text__c", "field_frtxz__c", "title_bold__c", "value_bold__c"])
                            .queryTemplate(QueryTemplate.AND(["feishu_message_card__c": QueryOperator.EQ(cardCfgId)]))
                            .orderBy(["display_order__c": 1])
                            .build(),
                    SelectAttribute.builder().build())
            if (perr) {
                log.error("飞书消息卡片变量查询失败：" + perrorMessage)
                return
            }
            List params = pQueryResult.dataList as List
            LinkedHashSet colSet = new LinkedHashSet()
            colSet.add("_id")
            params.each { pi ->
                String api = pi["single_line_text__c"] as String
                if (api) colSet.add(api)
            }
            List columns = new ArrayList(colSet)
            Map row = null
            if (columns.size() > 1) {
                Map fetched = Fx.object.findById(FEISHU_ROW_OBJECT_API, tenantDataId,
                        FQLAttribute.builder().columns(columns).build(),
                        SelectAttribute.builder()
                                .needOptionLabel(true)
                                .fillExtendInfo(true)
                                .convertQuoteForView(true)
                                .build()).result() as Map
                if (fetched) {
                    row = fetched
                }
            }
            if (row == null) {
                return
            }
            String contentBody = ""
            params.each { item ->
                String fieldAPI = item["single_line_text__c"] as String
                String displayName = item["field_frtxz__c"] as String
                Boolean titleBold = item["title_bold__c"] as Boolean
                Boolean valueBold = item["value_bold__c"] as Boolean
                String value = displayFromRow(row, fieldAPI)
                if (titleBold) {
                    displayName = "**" + displayName + "**"
                }
                if (valueBold) {
                    value = "**" + value + "**"
                }
                if (contentBody == "") {
                    contentBody = displayName + "：" + value + "\n"
                } else {
                    contentBody += displayName + "：" + value + "\n"
                }
            }
            String bContent = map["field_8yXhs__c__o"] as String
            if (!bContent) {
                return
            }
            bContent = bContent.replace("{{contentBody}}", contentBody)
            bContent = bContent.replace("{{subtitle}}", map["name"] as String)
            bContent = bContent.replace("{{title}}", map["card_title__c"] as String)
            bContent = bContent.replace("{{theme_color}}", map["theme_color__c"] as String)
            bContent = bContent.replace("{{objectId}}", tenantDataId)
            bContent = bContent.replace("objdetail/LeadsObj/", "objdetail/" + FEISHU_ROW_OBJECT_API + "/")
            DateTime now = DateTime.now()
            Long timestamp = ((now.toTimestamp() as Long) / 1000L) as Long
            bContent = bContent.replace("{{timestamp}}", timestamp as String)
            String stringToSign = timestamp + "\n" + FEISHU_SIGN_SECRET
            Mac mac = Mac.getInstance("HmacSHA256")
            mac.init(new SecretKeySpec(stringToSign.getBytes(StandardCharsets.UTF_8), "HmacSHA256"))
            byte[] signData = mac.doFinal("".getBytes("UTF-8"))
            bContent = bContent.replace("{{sign}}", Fx.crypto.base64.encode(signData))
            Map bodyContent = Fx.json.parse(bContent)
            StringBody body = StringBody.builder().content(bodyContent).build()
            Request request = Request.builder()
                    .method("POST")
                    .url(Fx.global.findByApiName("var_fu8eo__g")[1] as String)
                    .timeout(7000)
                    .retryCount(0)
                    .header("Content-Type", "application/json")
                    .body(body)
                    .build()
            def (Boolean httpErr, HttpResult httpResult, String httpMsg) = Fx.http.execute(request)
            if (httpErr || httpResult.statusCode != 200) {
                log.info("飞书推送失败：" + httpResult)
            } else {
                log.info("飞书推送结果：" + httpResult.content)
            }
        }
    }
    // ---------- 【同步后飞书推送】新增结束 ----------

    /**
     * 同步前函数,支持数据过滤
     */
    @Override
    IntegrationStreamSync.BeforeSyncResult executeBeforeSync(FunctionContext context, IntegrationStreamSync.BeforeSyncArg arg) {
        Integer sourceEventType = arg.getSourceEventType() //源系统触发事件-已废弃,请勿使用

        String tenantId = arg.getSourceTenantId() // 企业id
        String sourceObjectApiName = arg.getSourceObjectApiName() // 源系统对象apiName
        String destObjectApiName = arg.getDestObjectApiName() // 目标系统对象apiName
        ErpObjectData objectData = arg.getObjectData() // 来源系统主对象字段信息
        Map<String, List<ErpObjectData>> details = arg.getDetails() // 来源系统从对象信息 key:从对象apiName value:从对象字段信息列表
        String sourceDataId = arg.getSourceDataId() // 源系统数据id，只有crm->erp方向有这个字段

        String name = objectData != null ? objectData.getName() : ""
        def value = objectData != null ? objectData["属性"] : null

        // 返回null表示什么都不修改
//        return null

        def data = new IntegrationStreamSync.BeforeSyncData();
        data.setIsExec(true) // 为false 数据过滤,不做同步
        data.setIsCover(true) // 不给值或为false 不修改源数据
        data.setObjectData(null) // 替换源数据,为null主从对象都不做替换 如果只需要替换从对象，可以设置 data.setObjectData(objectData)
        data.setDetails(null) // 替换从对象信息,为null不做替换 key:从对象apiName value:从对象信息列表

        def result = new IntegrationStreamSync.BeforeSyncResult()
        result.setCode("0") // 返回结果状态 0为正常,其他都是失败
        result.setMessage("success") // 返回的错误信息
        result.setData(data)
        return result
    }

    /**
     * 同步中函数：写入目标系统之前
     * 函数执行后，在函数中编写的映射值修改，企业id和对象apiName不会更改。
     */
    @Override
    IntegrationStreamSync.DuringSyncResult executeDuringSync(FunctionContext context, IntegrationStreamSync.DuringSyncArg arg) {
        String tenantId = arg.getSourceTenantId() // 企业id
        String sourceObjectApiName = arg.getSourceObjectApiName() // 源系统对象apiName
        String destObjectApiName = arg.getDestObjectApiName() // 目标系统对象apiName
        ErpObjectData objectData = arg.getObjectData() // 目标系统主对象字段信息
        Map<String, List<ErpObjectData>> details = arg.getDetails()
        // 目标系统从对象信息,只有新增动作这个字段才有值 key:从对象apiName value:从对象字段信息列表
        Integer destEventType = arg.getDestEventType() // 目标系统执行动作 1、新增 2、修改 3、作废

        // 返回null表示什么都不修改
//        return null
        String name = objectData != null ? objectData.getName() : ""
        def value = objectData != null ? objectData.get("属性") : null

        ErpObjectData.ErpExtendData masterExtendData = objectData.getOrCretaErpExtendData(); //添加扩展值
        masterExtendData.setRemoveFields(["field1","field2"]) //设置删除的字段名
        masterExtendData.setAddData(["field3": "value3", "field4": "value4"]) //设置新增的数据

        def data = new IntegrationStreamSync.DuringSyncData()
        data.setObjectData(arg.getObjectData()) // 替换主对象字段信息,为null主从对象都不做替换 如果只需要替换从对象，可以设置 data.setObjectData(objectData)
        data.setDetails(arg.getDetails()) // 替换从对象字段信息,为null不做替换 key:从对象apiName value:从对象字段信息列表

        data.setDetailCover(true); // 为true时,以返回的details为准,覆盖从对象数据

        def result = new IntegrationStreamSync.DuringSyncResult()
        result.setCode("0") // 返回结果状态 0为正常,其他都是失败
        result.setMessage("success") // 返回的错误信息
        result.setData(data)
        return result
    }

    /**
     * 同步后函数,数据同步不会受到影响
     */
    @Override
    IntegrationStreamSync.AfterSyncResult executeAfterSync(FunctionContext context, IntegrationStreamSync.AfterSyncArg arg) {
        Integer sourceEventType = arg.getSourceEventType() //源系统触发事件-已废弃,请勿使用

        String tenantId = arg.getSourceTenantId() // 企业id
        String sourceObjectApiName = arg.getSourceObjectApiName() // 源系统对象apiName
        String destObjectApiName = arg.getDestObjectApiName() // 目标系统对象apiName
        String sourceDataId = arg.getSourceDataId() // 源系统数据id，只有crm->erp方向有这个字段
        ErpObjectData objectData = arg.getObjectData() // 目标系统主对象字段信息
        Map<String, List<ErpObjectData>> details = arg.getDetails()
        // 目标系统从对象信息,只有新增动作这个字段才有值 key:从对象apiName value:从对象字段信息列表
        Integer destEventType = arg.getDestEventType() // 目标系统执行动作 1、新增 2、修改 3、作废
        CompleteDataWriteMqData writeData = arg.getCompleteDataWriteResult() // 同步目标数据结果
        int code = writeData.getErrCode() // 0为正常,其他为失败接口返回的错误码
        String msg = writeData.getErrMsg() // 失败接口返回的错误信息
        Integer destTenantType = writeData.getDestTenantType() // 目标系统 1.纷享CRM 2.ERP
        CompleteDataWriteMqData.WriteResult writeResult = writeData.getWriteResult() // 同步主数据结果
        int errCode = writeResult.getErrCode() //主数据结果，0为正常,其他为失败接口返回的错误码
        String errMsg = writeResult.getErrMsg() // 主数据失败返回的错误信息
        SimpleSyncData simpleSyncData = writeResult.getSimpleSyncData() // 同步数据简略信息
        String destDataId = simpleSyncData.getDestDataId() // 目标系统数据id
        String destDataName = simpleSyncData.getDestDataName() // 目标系统数据主属性
        Map<String, ErpObjectData> destDetailSyncDataIdAndDestDataMap = writeResult.getDestDetailSyncDataIdAndDestDataMap()
        // 目标对象明细
        List<CompleteDataWriteMqData.WriteResult> results = writeData.getDetailWriteResults() // 同步明细数据结果

        // ---------- 原有逻辑：回写目标对象（认证状态等）----------
        Map updateMap = new LinkedHashMap()
        updateMap.put("authentication_status__c", "option_already_authenticated__c")
        updateMap.put("origin_source", 0)
        def (Boolean upErr, Map upData, String upMsg) = Fx.object.update(destObjectApiName, destDataId, updateMap, UpdateAttribute.builder().triggerWorkflow(true).build())
        if (upErr) {
            log.error("更新失败: " + (upMsg ?: ""))
        } else {
            log.info("dataId=" + destDataId)
        }
        // ---------- 原有逻辑结束 ----------

        // ---------- 【同步后飞书推送】新增：主数据同步成功且目标为租户时推送（卡片字段绑定 tenant__c）----------
        if (errCode == 0 && destDataId && FEISHU_ROW_OBJECT_API.equals(destObjectApiName)) {
            try {
                pushFeishuMessageCard(destDataId as String)
            } catch (Throwable t) {
                log.error("飞书卡片推送异常：" + (t.getMessage() ?: t.toString()))
            }
        }
        // ---------- 新增结束 ----------

        def result = new IntegrationStreamSync.AfterSyncResult()
        result.setCode("0")
        result.setMessage("success")
        return result
    }

    //debug 时候的入口方法
    Object debug(FunctionContext context, Map arg) {
        def r = new IntegrationStreamSync.AfterSyncResult()
        r.setCode("0")
        r.setMessage("success")
        return r
    }
}

/**
 * @author 纷享-刘喆斌
 * @codeName 【工作流】线索转换为租户和商机
 * @description 将线索一转二，转化成租户和商机，调用映射规则
租户：map_615jh__c
商机：map_e8qzy__c 商机名称为：客户名称+大模型用途/场景+部署偏好+”商机“ 
商机上挂租户
新建完成后将线索状态更新为已转换
 * @createTime 2026-02-03
 * @bindingObjectLabel 销售线索
 * @bindingObjectApiName LeadsObj
 * @函数需求编号
 */
String dataId = context.data._id as String
String leads_pool_id = context.data.leads_pool_id as String
List llm_usages_scenarios = context.data.llm_usages_scenarios__c as List
String deployment_preference = context.data.deployment_preference__c as String
String companyName = context.data.company as String

String llm_usages_scenarios_str = ""
if (llm_usages_scenarios) {
  llm_usages_scenarios_str = llm_usages_scenarios[0] as String
  llm_usages_scenarios_str = Fx.object.getOptionName("LeadsObj", "llm_usages_scenarios__c", llm_usages_scenarios_str)[1] as String
}

String deployment_preference_str = ""
if (deployment_preference) {
  deployment_preference_str = Fx.object.getOptionName("LeadsObj", "deployment_preference__c", deployment_preference)[1] as String
}

// 客户姓名 + 时间戳
String customerName = companyName ?: ""
String nameWithTs = customerName + String.valueOf(System.currentTimeMillis())

def ownerRaw = context.data.owner
List ownerList = ownerRaw instanceof List ? ownerRaw as List : (ownerRaw ? [ownerRaw] : [])

Map masterData = [
  "company": (companyName ?: "") as String,
  "name": (nameWithTs ?: "") as String,
  "field_222__c": (dataId ?: "") as String
] as Map<String,Object>
if (ownerList) masterData["owner"] = ownerList

Map detailData = [:]

def (Boolean error, Map data, String errorMessage) = Fx.object.copyByRule('LeadsObj', dataId, 'map_615jh__c', masterData, detailData)
if (error) {
  log.info("创建租户失败，原因：" + errorMessage)
} else {
  log.info("创建租户成功")
  String tenantId = (data?._id as String) ?: ((data?.get("data") as Map)?._id as String) ?: ""
  if (tenantId) {
    masterData["account__c"] = tenantId
  }
}

 masterData["sales_process_id"] = "69786bdfc1a13200062654e5"
 masterData["sales_stage"] = "1"
def (Boolean error2, Map data2, String errorMessage2) = Fx.object.copyByRule('LeadsObj', dataId, 'map_e8qzy__c', masterData, detailData)
if (error2) {
  log.info("创建商机失败，原因：" + errorMessage2)
} else {
  log.info("创建商机成功")
  String opportunityId = (data2?._id as String) ?: ((data2?.get("data") as Map)?._id as String) ?: ""
  if (opportunityId) {
    def match_res = Fx.stage.matchDef("NewOpportunityObj", opportunityId, "1000")[1] as Map
    String sourceWorkflowId = "69786bdfc1a13200062654e5"
    Map updateData = [
      "sales_process_id": sourceWorkflowId,
      "sales_stage": "1"
    ]
    Fx.object.update("NewOpportunityObj", opportunityId, updateData, UpdateAttribute.builder().triggerWorkflow(true).build())
    log.info("trigger success")
  }
}

if (leads_pool_id && leads_pool_id != (context.data.leads_pool_id as String)) {
  def (Boolean error3, Map data3, String errorMessage3) = Fx.crm.leads.move(dataId, leads_pool_id)
  if (error3) {
    log.info("线索转移失败，原因：" + errorMessage3)
  } else {
    log.info("线索转移成功")
  }
} 

def (Boolean error4, Map data4, String errorMessage4) = Fx.object.update("LeadsObj", dataId, ["single_choice__c": "option_already_transferred_out__c"], UpdateAttribute.builder().triggerWorkflow(true).build())
if (error4) {
  log.info("更新线索状态失败，原因：" + errorMessage4)
} else {
  log.info("更新线索状态成功")
}

/**
 * @author 纷享-刘喆斌
 * @codeName 【流程】国内官网线索推送飞书群
 * @description 国内官网线索推送飞书群
 * @createTime 2026-03-20
 * @bindingObjectLabel 销售线索
 * @bindingObjectApiName LeadsObj
 * @函数需求编号
 */
import javax.crypto.Mac;
import javax.crypto.spec.SecretKeySpec;
import java.nio.charset.StandardCharsets;
import org.apache.commons.codec.binary.Base64;
def (Boolean error, QueryResult queryResult, String errorMessage) = Fx.object.find("feishu_message_card__c", //对象apiName
        FQLAttribute.builder()
                .columns(["_id", "name","card_structure__c","field_8yXhs__c","card_title__c","theme_color__c"]) //需要返回的字段
                .queryTemplate(QueryTemplate.AND(["name": QueryOperator.EQ("国内官网线索通知")])) //查询条件
                .build(),
       SelectAttribute.builder()
                .build())
if (error) {
    log.error("获取对象异常" + errorMessage)

} else {
    log.info("获取对象成功" + queryResult)
    // findById 开 needOptionLabel / fillExtendInfo / convertQuoteForView；字段__r
    def asCellText = { Object v ->
        if (v == null) return ""
        if (v instanceof String) return (v as String).trim()
        if (v instanceof List) {
            List parts = []
            (v as List).each { it ->
                if (it instanceof Map) {
                    Map m = it as Map
                    String p = m["label"] as String
                    if (p) parts.add(p)
                } else if (it != null) {
                    String s = (it as String)?.trim()
                    if (s) parts.add(s)
                }
            }
            return parts.join(", ")
        }
        if (v instanceof Map) {
            Map m = v as Map
            return (m["label"] ?: "") as String
        }
        return (v as String) ?: ""
    }
    def displayFromRow = { Map row, String fieldAPI ->
        if (!fieldAPI) return ""
        String s = asCellText(row[fieldAPI + "__r"])
        if (s) return s
        return asCellText(row[fieldAPI])
    }
    def dataList = queryResult.dataList as List //数据列表
    dataList.each {
        e ->
            Map map = e as Map
            def id = map['_id']
            //获取当前消息卡片的所有卡片参数
            def (Boolean perror, QueryResult pQueryResult, String perrorMessage) = Fx.object.find("message_card_variable__c", //对象apiName
                    FQLAttribute.builder()
                            .columns(["placeholder__c","single_line_text__c","field_frtxz__c","field_86m09__c","title_bold__c","value_bold__c"]) //需要返回的字段
                            .queryTemplate(QueryTemplate.AND(["feishu_message_card__c": QueryOperator.EQ(id)])) 
                            .orderBy(["display_order__c": 1]) //排序
                            .build(),
                   SelectAttribute.builder()
                            .build())
            if ( perror ){
              log.error("查询消息卡片参数时发生错误："+perror)
              return
            }

            //获取获取当前消息卡片的所有卡片参数数值
            log.info("消息卡片参数："+ pQueryResult)
            List params = pQueryResult.dataList as List
            String leadId = (context.data["_id"] as String) ?: ""
            LinkedHashSet colSet = new LinkedHashSet()
            colSet.add("_id")
            params.each { pi ->
                String api = pi["single_line_text__c"] as String
                if (api) colSet.add(api)
            }
            List columns = new ArrayList(colSet)
            Map row = context.data as Map
            if (leadId && columns.size() > 1) {
                Map fetched = Fx.object.findById("LeadsObj", leadId,
                        FQLAttribute.builder().columns(columns).build(),
                        SelectAttribute.builder()
                                .needOptionLabel(true)
                                .fillExtendInfo(true)
                                .convertQuoteForView(true)
                                .build()).result() as Map
                if (fetched) row = fetched
            }
            String contentBody = ""
            params.each {
              item ->
              String fieldAPI = item['single_line_text__c'] as String
              String displayName = item['field_frtxz__c'] as String
              Boolean titleBold = item['title_bold__c'] as Boolean
              Boolean valueBold = item['value_bold__c'] as Boolean
              String value = displayFromRow(row, fieldAPI)
              if (titleBold ){
                displayName = "**" + displayName + "**"
              }
              if (valueBold ){
                value = "**" + value + "**"
              }
              if( contentBody == "" ){
                contentBody = displayName + "：" + value + "\n"
              }else{
                contentBody += displayName + "：" + value + "\n"
              }

            }
            String bContent = map['field_8yXhs__c__o'] as String
