/**
 * @author 纷享-刘喆斌
 * @codeName 飞书审批状态回调
 * @description 仅处理指定审批码的飞书审批状态回调，并回写CRM
 * @createTime 2026-02-03
 * @bindingObjectLabel --
 * @bindingObjectApiName NONE
 * @函数需求编号
 * 开发者证书：
 */

/**
 * @type classes
 * @returntype
 * @namespace apl_controller
 */
import javax.crypto.Cipher
import javax.crypto.spec.IvParameterSpec
import javax.crypto.spec.SecretKeySpec
import java.security.MessageDigest
import java.util.Base64
import java.util.Arrays
import java.util.LinkedHashMap
import com.fxiaoke.apl.http.Request
import com.fxiaoke.apl.http.StringBody
import com.fxiaoke.apl.http.HttpResult
import com.fxiaoke.kernel.query.QueryOperator
import com.fxiaoke.kernel.object.UpdateAttribute

@AplController(baseUrl = "/apl")
class AplCtrlXdw4C {

    private static final String ENCRYPT_KEY = "fxiaoke"
    private static final String VERIFICATION_TOKEN = "rj4B4hvpJh8BL6tqXMrxKnlmd4jcgImv"

    // 审批码 → CRM 对象配置映射，新增审批在此追加
    private static final Map APPROVAL_CONFIG = [
        // 透支申请
        "78A08C46-DFFC-4141-8F88-0C3AB294C64D": [
            obj:           "overdraft_application__c",
            instanceField: "field_6s4go__c",
            statusField:   "application_status__c"
        ],
        // 合同审批
        "0BE2B6D3-55A6-4F4F-B4F7-1CF29B1BA7BE": [
            obj:           "SaleContractObj",
            instanceField: "field_R2wnq__c",
            statusField:   "approval_status__c"
        ]
    ]

    @AplRequestMapping(value = "/query", method = RequestMethod.POST)
    public HttpResponse query(HttpRequest request) {
        byte[] raw = request?.getBody()
        String requestBody = raw ? new String(raw, "UTF-8") : ""
        Map payload = new LinkedHashMap()
        try {
            payload = Fx.json.parse(requestBody) as Map
        } catch (Exception e) {
            Map resp = new LinkedHashMap()
            resp.put("code", 500)
            resp.put("msg", "Invalid JSON: " + e.getMessage())
            return HttpResponse.ok().body(Fx.json.toJson(resp))
        }

        if (payload?.containsKey("body")) {
            try {
                String wrapped = payload.get("body") as String
                String innerJson = new String(Base64.getDecoder().decode(wrapped), "UTF-8")
                payload = Fx.json.parse(innerJson) as Map
                log.info("解析body后的原始数据: {}" + innerJson)
            } catch (Exception e) {
                Map resp2 = new LinkedHashMap()
                resp2.put("code", 500)
                resp2.put("msg", "Invalid body base64: " + e.getMessage())
                log.info("解析body的base64失败"+ e)
                return HttpResponse.ok().body(Fx.json.toJson(resp2))
            }
        }

        if (payload?.containsKey("encrypt")) {
            try {
                String encryptedData = payload.get("encrypt") as String
                String decryptedJson = decryptLarkData(encryptedData, ENCRYPT_KEY)
                payload = Fx.json.parse(decryptedJson) as Map
                log.info("解密后的飞书事件数据: {}"+ decryptedJson)
            } catch (Exception e) {
                Map resp3 = new LinkedHashMap()
                resp3.put("code", 500)
                resp3.put("msg", "Decrypt failed: " + e.getMessage())
                log.info("飞书数据解密失败"+ e)
                return HttpResponse.ok().body(Fx.json.toJson(resp3))
            }
        }

        // Token验证
        String token = payload?.get("token") as String
        if (token && token != VERIFICATION_TOKEN) {
            Map resp4 = new LinkedHashMap()
            resp4.put("code", 403)
            resp4.put("msg", "invalid token")
            log.warn("Token验证失败，收到的token: {}"+token)
            return HttpResponse.ok().body(Fx.json.toJson(resp4))
        }

        // URL验证（飞书初始校验）
        String type = payload?.get("type") as String
        String challenge = payload?.get("challenge") as String
        if ("url_verification" == type && challenge) {
            Map ch = new LinkedHashMap()
            ch.put("challenge", challenge)
            log.info("处理飞书URL验证，返回challenge: {}"+challenge)
            return HttpResponse.ok()
                    .header("Content-Type", "application/json;charset=utf-8")
                    .body(Fx.json.toJson(ch))
        }

        // 处理审批事件
        if (payload?.containsKey("event")) {
            try {
                Map ev = payload.get("event") as Map
                String eventApprovalCode = ev?.get("approval_code") as String
                String instanceCode = ev?.get("instance_code") as String
                String status = ev?.get("status") as String
                log.info("收到审批事件，approval_code=" + eventApprovalCode + " instance_code=" + instanceCode + " status=" + status)

                // 根据审批码查配置，未配置的跳过
                Map cfg = APPROVAL_CONFIG.get(eventApprovalCode) as Map
                if (!cfg) {
                    log.info("审批码未配置，跳过：" + eventApprovalCode)
                    Map skip = new LinkedHashMap()
                    skip.put("code", 0)
                    skip.put("message", "skip non-target approval")
                    return HttpResponse.ok()
                            .header("Content-Type", "application/json;charset=utf-8")
                            .body(Fx.json.toJson(skip))
                }

                if (instanceCode && status) {
                    Map STATUS_ENUM = new LinkedHashMap()
                    STATUS_ENUM.put("NEW",       "option_newly_built__c")
                    STATUS_ENUM.put("PENDING",   "option_approval_in_progress__c")
                    STATUS_ENUM.put("APPROVED",  "option_approval_passed__c")
                    STATUS_ENUM.put("REJECTED",  "option_approval_rejection__c")
                    STATUS_ENUM.put("EXPIRED",   "option_expired__c")
                    String crmStatus = STATUS_ENUM.get(status) as String
                    if (!crmStatus) {
                        log.warn("未匹配到CRM状态值，飞书状态：" + status)
                        crmStatus = "other"
                    }

                    String objName     = cfg.get("obj") as String
                    String fieldInst   = cfg.get("instanceField") as String
                    String fieldStatus = cfg.get("statusField") as String
                    Map cond = new LinkedHashMap()
                    cond.put(fieldInst, QueryOperator.EQ(instanceCode))
                    Map fields = new LinkedHashMap()
                    fields.put(fieldStatus, crmStatus)

                    Fx.object.update(objName, QueryTemplate.AND(cond), fields,
                                     UpdateAttribute.builder().triggerWorkflow(true).build())
                    log.info("CRM回写成功，对象=" + objName + " instance=" + instanceCode + " status=" + crmStatus)
                } else {
                    log.info("审批事件缺少 instanceCode 或 status：" + Fx.json.toJson(ev))
                }
            } catch (Exception e) {
                log.info("处理审批事件/回写CRM失败：" + e)
            }
        }

        Map ok = new LinkedHashMap()
        ok.put("code", 0)
        ok.put("message", "success")
        ok.put("data", payload)
        log.info("请求处理完成，返回成功响应")
        return HttpResponse.ok()
                .header("Content-Type", "application/json;charset=utf-8")
                .body(Fx.json.toJson(ok))
    }


    private String decryptLarkData(String encrypt, String key) {
        byte[] keySha = sha256(key)
        byte[] decoded = Base64.getDecoder().decode(encrypt)
        byte[] iv = Arrays.copyOfRange(decoded, 0, 16)
        byte[] cipherBytes = Arrays.copyOfRange(decoded, 16, decoded.length)
        return aesCbcDecryptBytes(cipherBytes, keySha, iv)
    }

    // SHA256方法
    private byte[] sha256(String s) {
        MessageDigest md = MessageDigest.getInstance("SHA-256")
        md.update(s.getBytes("UTF-8"))
        return md.digest()
    }

    // AES解密方法
    private String aesCbcDecryptBytes(byte[] cipherBytes, byte[] keyBytes, byte[] ivBytes) {
        Cipher cipher = Cipher.getInstance("AES/CBC/PKCS5Padding")
        SecretKeySpec secretKey = new SecretKeySpec(keyBytes, "AES")
        IvParameterSpec ivSpec = new IvParameterSpec(ivBytes)
        cipher.init(Cipher.DECRYPT_MODE, secretKey, ivSpec)
        byte[] plain = cipher.doFinal(cipherBytes)
        return new String(plain, "UTF-8")
    }

    // 订阅
    @AplRequestMapping(value = "/subscribe", method = RequestMethod.POST)
    public HttpResponse subscribe(HttpRequest request) {
        String approvalCode = ""
        try {
            byte[] raw = request?.getBody()
            String requestBody = raw ? new String(raw, "UTF-8") : ""
            if (requestBody) {
                Map p = Fx.json.parse(requestBody) as Map
                Object v = p?.get("approval_code")
                if (v instanceof String) { approvalCode = v as String }
            }
        } catch (Exception e) {}
        if (!approvalCode) {
            Map resp = new LinkedHashMap()
            resp.put("code", 400)
            resp.put("msg", "missing approval_code")
            return HttpResponse.ok().header("Content-Type", "application/json;charset=utf-8").body(Fx.json.toJson(resp))
        }

        String token = PubLibFeishuToken.getTenantAccessToken()
        String url = "https://open.feishu.cn/open-apis/approval/v4/approvals/" + approvalCode + "/subscribe"
        Map body = new LinkedHashMap()
        Request req = Request.builder()
                .method("POST")
                .url(url)
                .header("Content-Type", "application/json;charset=utf-8")
                .timeout(10000)
                .body(StringBody.builder().content(Fx.json.toJson(body)).build())
                .build()
        req.getHeaders().put("Authorization", java.util.Collections.singletonList("Bearer " + token))
        def (Boolean error, HttpResult result, String message) = Fx.http.execute(req)
        Map out = new LinkedHashMap()
        if (error || !result) {
            out.put("code", 500)
            out.put("msg", message ? message : "http error")
        } else {
            Object content = result.content
            if (content instanceof Map) {
                out = content as Map
            } else if (content instanceof String) {
                try { out = Fx.json.parse(content as String) as Map } catch (Exception e) {
                    out.put("code", result.statusCode)
                    out.put("raw", content as String)
                }
            } else {
                out.put("code", result.statusCode)
                out.put("raw", String.valueOf(content))
