  // 7. 合同盖章份数
  BigDecimal copies = getNum("contract_seal_number__c") 
  if (copies != null) items.add([id: "widget17022841363600001", type: "number", value: copies])


  // ==================== 单选 & 多选类字段 ====================

  // 8. 合同类型 (单选)
  String contractTypeCrm = getStr("contract_type__c") 
  String contractTypeFs = DICT_CONTRACT_TYPE.get(contractTypeCrm)
  if (contractTypeFs) items.add([id: "widget17022839766140001", type: "radioV2", value: contractTypeFs])

  // 9. 我方单位名称 (单选)
  String ourCompanyCrm = getStr("our_company_name__c")
