def createApproval = { String token, String initiatorId, String formJson ->
  Map body = [
    approval_code: APPROVAL_CODE,
    open_id:       initiatorId,
    form:          formJson,
   auto_submit:   true
  ]
  Request req = Request.builder().method("POST")
    .url("https://open.feishu.cn/open-apis/approval/v4/instances")
    .header("Content-Type","application/json; charset=utf-8")
    .header("Authorization","Bearer " + token)
    .timeout(15000)
    .body(StringBody.builder().content(Fx.json.toJson(body)).build())
    .build()
  log.info("创建审批入参：" + Fx.json.toJson(body))
  def (Boolean error, HttpResult result, String message) = Fx.http.execute(req)
  String respText = (result?.content instanceof String) ? (result.content as String) : Fx.json.toJson(result?.content)
  log.info("创建审批响应：status=" + (result ? result.statusCode : "null") + ", content=" + (respText ?: ""))
  if (error || !result || result.statusCode != 200) {
    return [ok:false, message:(message ?: "HTTP " + (result ? result.statusCode : "null"))]
  }
  Map ret = [:]
  if (result.content instanceof String) {
    try { ret = Fx.json.parse(result.content as String) as Map } catch (Exception e) { ret = [:] }
  } else { ret = result.content as Map }
  def codeRaw = ret.get("code")
  Integer code = (codeRaw instanceof Number) ? (codeRaw as Integer) : ((codeRaw ?: "-1").toString() as Integer)
  if (code != 0) return [ok:false, message:(ret.get("msg") as String) ?: "创建审批失败"]
  Map dataMap = (ret.get("data") as Map) ?: [:]
  String instanceCode = (dataMap.get("instance_code") as String) ?: ""
  if (!instanceCode) return [ok:false, message:"instance_code为空"]
  log.info("审批创建成功，instanceCode=" + instanceCode)
  [ok:true, instance_code: instanceCode]
}

