  return [success:false, message:"无法获取负责人飞书 open_id，请确认负责人已绑定飞书账号"]
}

def formJson = buildFormJsonByDef(tenantToken, initiatorOpenId)
log.info("表单JSON：" + formJson)
if (!formJson || formJson == "[]") {
  return [success:false, message:"未能生成有效表单JSON"]
}

// 校验表单控件 id 是否在审批定义中
def defIdsRes = fetchDefinitionIds(tenantToken) as Map
if (!(defIdsRes.get("ok") as Boolean)) {
  return [success:false, message:(defIdsRes.get("message") as String) ?: "获取审批定义失败"]
}
List wantItems  = Fx.json.parseList(formJson) as List
List wantIds    = wantItems?.collect { (it as Map).get("id")?.toString() }?.findAll { it } ?: []
List allowedIds = (defIdsRes.get("ids") as List) ?: []
List missing    = wantIds.findAll { !allowedIds.contains(it) }
if (missing && missing.size() > 0) {
  return [success:false, message:"审批定义中未找到表单控件：" + (missing[0] as String)]
}

def ap = createApproval(tenantToken, initiatorOpenId, formJson) as Map
log.info("创建审批返回：" + Fx.json.toJson(ap))
if (!(ap.get("ok") as Boolean)) {
  def msg = (ap.get("message") as String) ?: "创建审批失败"
  log.error("流程失败：" + msg)
  return [success:false, message:msg]
}

updateCrm(recordId, STATUS_ENUM.APPROVING, ap.get("instance_code") as String)
log.info("流程完成，已回填审批实例并置为审批中")
return [success:true, message:"审批发起成功", instance_code:ap.get("instance_code") as String]

