    Map dataMap = (ret.get("data") as Map) ?: [:]
    String instanceCode = (dataMap.get("instance_code") as String) ?: ""
    if (!instanceCode) return [ok:false, message:"instance_code为空"]
    log.info("审批创建成功，instanceCode=" + instanceCode)
    return [ok:true, instance_code: instanceCode]
  }
  Map res = callOnce("https://open.feishu.cn/open-apis/approval/v4/instances") as Map
  return res
}

def fetchDefinitionIds = { String token ->
  String url = "https://open.feishu.cn/open-apis/approval/v4/approvals/" + APPROVAL_CODE 
  Request req = Request.builder()
    .method("GET")
    .url(url)
    .header("Content-Type","application/json")
    .header("Authorization","Bearer " + token)
    .timeout(15000)
    .build()
  def(Boolean error, HttpResult result, String message) = Fx.http.execute(req)
  if (error || !result || result.statusCode != 200) return [ok:false, message:(message ?: ("HTTP " + (result ? result.statusCode : "null")))]
  Map ret = [:]
  if (result.content instanceof String) { ret = Fx.json.parse(result.content as String) as Map } else if (result.content instanceof Map) { ret = result.content as Map }
  Map data = (ret.get("data") as Map) ?: [:]
  String formStr = (data.get("form") as String) ?: "[]"
  List lst = Fx.json.parseList(formStr) as List
  List ids = lst?.collect { (it as Map).get("id")?.toString() }?.findAll { it } ?: []
  [ok:true, ids: ids]
}

String tenantToken = PubLibFeishuToken.getTenantAccessToken() as String
if (!tenantToken) {
  log.error("流程失败：获取Token失败")
  return [success:false, message:"获取Token失败"]
}
def formJson = buildFormJsonByDef(tenantToken as String)
if (!formJson) {
  fetchDefinition(tenantToken as String)
  return [success:false, message:"缺少飞书表单映射({id,value}数组)"]
}
def defIdsRes = fetchDefinitionIds(tenantToken as String) as Map
if (!(defIdsRes.get("ok") as Boolean)) {
  return [success:false, message:(defIdsRes.get("message") as String) ?: "获取审批定义失败"]
}
List wantItems = Fx.json.parseList(formJson) as List
List wantIds = wantItems?.collect { (it as Map).get("id")?.toString() }?.findAll { it } ?: []
List allowedIds = (defIdsRes.get("ids") as List) ?: []
List missing = wantIds.findAll { !allowedIds.contains(it) }
if (missing && missing.size() > 0) {
  return [success:false, message:("审批定义中未找到表单控件：" + (missing[0] as String))]
}
def initiatorOpenId = resolveOwnerOpenId(cd) as String
if (!initiatorOpenId) {
  log.error("流程失败：无法获取负责人飞书 open_id，请确认负责人已绑定飞书账号")
  return [success:false, message:"无法获取负责人飞书 open_id"]
}

def ap = createApproval(tenantToken as String, initiatorOpenId, "open_id", formJson) as Map
log.info("创建审批返回Map=" + Fx.json.toJson(ap))
if (!(ap.get("ok") as Boolean)) {
  def msg = (ap.get("message") as String) ?: "创建审批失败"
  log.error("流程失败：" + msg)
  return [success:false, message: msg]
}
updateCrm(recordId, STATUS_ENUM.APPROVING, ap.get("instance_code") as String)
log.info("流程完成，已回填审批实例并置为审批中")
return [success:true, message:"审批发起成功", instance_code: ap.get("instance_code") as String]

