    /**
     * 同步后函数,数据同步不会受到影响
     */
    @Override
    IntegrationStreamSync.AfterSyncResult executeAfterSync(FunctionContext context, IntegrationStreamSync.AfterSyncArg arg) {
        CompleteDataWriteMqData writeData = arg.getCompleteDataWriteResult() // 同步目标数据结果
        String destObjectApiName = arg.getDestObjectApiName() // 目标系统对象apiName（消费明细对象）
        ErpObjectData objectData = arg.getObjectData() // 目标系统主对象字段信息
        if (objectData != null) {
            // 实际传进来的字段是 tenant_id__c，这里统一当作 subjectName 处理
            Object subVal = objectData.get("tenant_id__c")
            String subjectName = subVal == null ? "" : (subVal as String)
            if (subjectName) {
                log.info("[同步后函数] 开始处理 tenant_id__c 关联, destObjectApiName=" + destObjectApiName + ", subjectName=" + subjectName)
                try {
                    // 2. 先按租户 name 匹配，若未找到再按租户的 tenant_id__c 匹配
                    def (Boolean findErr1, QueryResult findResult1, String findMsg1) = Fx.object.find(
                        "tenant__c",
                        FQLAttribute.builder()
                            .columns(["_id"])
                            .queryTemplate(QueryTemplate.AND(["name": QueryOperator.EQ(subjectName)]))
                            .limit(1)
                            .build(),
                        SelectAttribute.builder().needInvalid(false).build()
                    )
                    QueryResult useRes = findResult1
                    Boolean useErr = findErr1
                    String useMsg = findMsg1
                    if (useErr || useRes == null || useRes.dataList == null || useRes.dataList.isEmpty()) {
                        def (Boolean findErr2, QueryResult findResult2, String findMsg2) = Fx.object.find(
                            "tenant__c",
                            FQLAttribute.builder()
                                .columns(["_id"])
                                .queryTemplate(QueryTemplate.AND(["tenant_id__c": QueryOperator.EQ(subjectName)]))
                                .limit(1)
                                .build(),
                            SelectAttribute.builder().needInvalid(false).build()
                        )
                        useErr = findErr2
                        useRes = findResult2
                        useMsg = findMsg2
                    }
                    if (!useErr && useRes != null && useRes.dataList != null && useRes.dataList.size() > 0) {
                        String tenantId = ((useRes.dataList.get(0) as Map).get("_id") ?: "") as String
                        if (tenantId) {
                            // 3. 回写当前消费明细记录，把 subject_id__c 更新为租户 _id
                            CompleteDataWriteMqData.WriteResult writeResult = writeData.getWriteResult()
                            SimpleSyncData simpleSyncData = writeResult != null ? writeResult.getSimpleSyncData() : null
                            String destDataId = simpleSyncData != null ? (simpleSyncData.getDestDataId() ?: "") : ""
                            if (destDataId) {
                                Map<String, Object> updateMap = ["subject_id__c": tenantId] as Map<String, Object>
                                def (Boolean updErr, Map updRes, String updMsg) = Fx.object.update(
                                    destObjectApiName,
                                    destDataId,
                                    updateMap,
                                    UpdateAttribute.builder().build()
                                )
                                if (updErr) {
                                    log.error("[同步后函数] 更新消费明细 subject_id__c 失败: " + (updMsg ?: "unknown"))
                                } else {
                                    log.info("[同步后函数] 已将 subject_id__c 关联到租户_id: " + tenantId)
                                }
                            }
                        }
                    } else if (useErr) {
                        log.error("[同步后函数] 查询租户失败: " + (useMsg ?: "unknown"))
                    }
                } catch (Exception ex) {
                    log.error("[同步后函数] 处理租户subject关联异常: " + ex.getMessage())
                }
            }
        }

        def result = new IntegrationStreamSync.AfterSyncResult()
        result.setCode("0") // 返回结果状态 0为正常,其他都是失败
        result.setMessage("success") // 返回的错误信息
        return result
    }

    //debug 时候的入口方法
    Object debug(FunctionContext context, Map arg) {
       return executeBeforeSync(context, json.parseObject("{}", IntegrationStreamSync.BeforeSyncArg))
    }
}

