        String sourceDataId = arg.getSourceDataId() // 源系统数据id，只有crm->erp方向有这个字段

        String subjectName = ((objectData as Map).get("subject_id") ?: "") as String
        log.info("subjectName: " + subjectName) 
        if (subjectName) {
            def (Boolean findErr, QueryResult findResult, String findMsg) = Fx.object.find(
                "tenant__c",
                FQLAttribute.builder()
                    .columns(["_id"])
                    .queryTemplate(QueryTemplate.AND(["name": QueryOperator.EQ(subjectName)]))
                    .build(),
                SelectAttribute.builder().build()
            )
            if (!findErr && findResult && findResult.dataList && findResult.dataList.size() > 0) {
                String matchedId = ((findResult.dataList.get(0) as Map).get("_id") ?: "") as String
