                }
            } else if (findErr) {
                log.error("查询租户失败: " + findMsg)
            }
        }

        def data = new IntegrationStreamSync.BeforeSyncData();
        data.setIsExec(true)
        data.setIsCover(true)
        data.setObjectData(objectData)
        data.setDetails(null)

        def result = new IntegrationStreamSync.BeforeSyncResult()
        result.setCode("0") // 返回结果状态 0为正常,其他都是失败
        result.setMessage("success") // 返回的错误信息
        result.setData(data)
        return result
    }

    /**
     * 同步中函数：写入目标系统之前
