/**
 * @author 纷享-刘喆斌
 * @codeName 【工作流】新建租户后关联/新建客户
 * @description 新建租户时，根据组织机构代码来查找是否有已有的客户，如果是，则将租户关联到此客户。如果不是，则新建一个客户，并关联租户到此客户。
 * @createTime 2026-02-02
 * @bindingObjectLabel 租户
 * @bindingObjectApiName tenant__c
 * @函数需求编号
 */

def tenantId = (context.data._id as String) ?: ""
def orgCode = (context.data.organization_code__c as String) ?: ""
def tenantName = (context.data.company_name__c as String) ?: ""

if (!orgCode) {
  log.info("组织机构代码为空")
}

// 客户主属性
Map customerData = [
  ("name"): (tenantName),
  ("uniform_social_credit_code"): orgCode
] as Map<String,Object>


// 创建客户
def (Boolean createError, Map createData, String createMsg) = Fx.object.create(
  "AccountObj",
  customerData,
  [:],
  CreateAttribute.builder().build()
)

String customerId = ""
if (createError) {
  customerId = ((createData?.get("_id")) as String) ?: ""
  if (!customerId) {
    return [success:false, message:(createMsg ?: "创建客户失败据")] 
  }
} else {
  customerId = ((createData?.get("_id")) as String) ?: ""
  if (!customerId) {
    def inner = (createData?.get("data") as Map) ?: [:]
    customerId = ((inner?.get("_id")) as String) ?: ""
  }
}

if (!customerId) {
  return [success:false, message:"未获取到客户ID"]
}

// 判断数据来源：origin_source==0 同步到机构认证公海池，否则同步到市场活动公海池
Object originVal = context?.data?.get("origin_source")
Integer originInt = null
if (originVal instanceof Number) { originInt = (originVal as Number).intValue() } else if (originVal != null) {
  try { originInt = Integer.valueOf(String.valueOf(originVal)) } catch (Exception ignore) {}
}
boolean isOriginZero = (originInt != null && originInt == 0)
String targetPoolName = isOriginZero ? "机构认证公海池" : "市场活动公海池"
String publicSeaId = ""
java.util.ArrayList cols = new java.util.ArrayList()
cols.add("_id")
cols.add("name")
// 查询目标公海池ID（HighSeasObj），根据名称匹配
java.util.LinkedHashMap qtMap = new java.util.LinkedHashMap()
qtMap.put("name", QueryOperator.EQ(targetPoolName))
def(Boolean hsErr, com.fxiaoke.functions.model.QueryResult hsRes, String hsMsg) = Fx.object.find(
  "HighSeasObj",
  FQLAttribute.builder().columns(cols).queryTemplate(QueryTemplate.AND(qtMap)).limit(1).build(),
  SelectAttribute.builder().build()
)
if (!hsErr && hsRes) {
  List hsItems = hsRes.getDataList() as List
  if (hsItems && hsItems.size() > 0) {
    Map first = hsItems.get(0) as Map
    publicSeaId = (first.get("_id") as String) ?: ""
  }
}
// 同步客户至目标公海池
if (publicSeaId && customerId) {
  try {
    Object mvRes = Fx.crm.account.move(customerId, publicSeaId)
    log.info("同步至公海池已触发，accountId=" + customerId + ", poolId=" + publicSeaId)
  } catch (Exception e) {
    log.info("同步至公海池失败：" + (e.getMessage() ?: ""))
  }
}

// 更新租户上的关联客户字段
// 回填租户上的关联客户字段
Map updateTenant = [
  ("customer__c"): customerId
] as Map<String,Object>

def (Boolean updErr, Map updData, String updMsg) = Fx.object.update(
  "tenant__c",
  tenantId,
  updateTenant,
  UpdateAttribute.builder().triggerWorkflow(true).build()
)

// 关联失败直接返回错误
if (updErr) {
  return [success:false, message:(updMsg ?: "租户关联客户失败")] 
}

// 成功返回客户ID
return [success:true, message:"租户已关联客户", customer_id: customerId]

String instanceCode = ""
if (syncArg && syncArg["objectData"]) {
  Map od = (syncArg["objectData"] as Map)
  if (od["instance_code"] != null) instanceCode = (od["instance_code"] as String)
}
if (!instanceCode) { return [code:"1", msg:"缺少instance_code", data:null] }
String token = PubLibFeishuToken.getTenantAccessToken()
if (!token) { return [code:"1", msg:"获取Token失败", data:null] }
String url = "https://open.feishu.cn/open-apis/approval/v4/instances/get" +
  "?instance_code=" + java.net.URLEncoder.encode(instanceCode, "UTF-8") +
  ""
def callOnce = { String u ->
  Request req = Request.builder().method("GET").url(u).timeout(15000).header("Content-Type", "application/json; charset=utf-8").header("Authorization", "Bearer " + token).build()
  def (Boolean error, HttpResult result, String errorMessage) = Fx.http.execute(req)
  String contentText = (result?.content instanceof String) ? (result.content as String) : Fx.json.toJson(result?.content)
  if (error || !result || result.statusCode != 200) { return [ok:false, message:(errorMessage ?: (contentText ?: ("HTTP " + (result ? result.statusCode : "null"))))] }
  Map resp = [:]
  if (result.content instanceof String) { try { resp = Fx.json.parse(result.content as String) as Map } catch (Exception e) { resp = [:] } } else { resp = result.content as Map }
  def codeRaw = resp.get("code")
  Integer code = (codeRaw instanceof Number) ? (codeRaw as Integer) : ((codeRaw ?: "-1").toString() as Integer)
  if (code != 0) { return [ok:false, message: (resp.get("msg") as String) ?: "接口返回错误"] }
  Map data = (resp.get("data") as Map) ?: [:]
  String status = (data.get("status") as String) ?: ""
  String ic = (data.get("instance_code") as String) ?: instanceCode
  String apptovalNum = (data.get("serial_number") as String)
  return [ok:true, data:[instance_code: ic, status: status,feishu_approval_number__c:apptovalNum, raw: data]]
}

Map r1 = callOnce(url) as Map
if (!(r1.get("ok") as Boolean)) {
  String alt = "https://open.feishu.cn/open-apis/approval/v4/instances/" + java.net.URLEncoder.encode(instanceCode, "UTF-8")
  Map r2 = callOnce(alt) as Map
  if (!(r2.get("ok") as Boolean)) { return [code:"1", msg:(r2.get("message") as String) ?: (r1.get("message") as String) ?: "请求失败", data:null] }
  return [code:"0", msg:"success", data:r2.get("data")]
}
return [code:"0", msg:"success", data:r1.get("data")]

/**
