if (error) {
  log.info("error:" + errorMessage)
}

/**
 * @author 纷享-刘喆斌
 * @codeName 【流程】线索 - 设置线索领取/分配后的自动回收时间
 * @description 工作日24小时未跟进、周末48小时未跟进则自动回收线索至未跟进线索池
 * @createTime 2026-01-27
 * @bindingObjectLabel 销售线索
 * @bindingObjectApiName LeadsObj
 * @函数需求编号
 */
DateTime receiveTime = context.data["assigned_time"] as DateTime; // 领取分配时间
DateTime recoveryTime = receiveTime
if( receiveTime){
  Date receiveDate = receiveTime.toDate(); // 领取分配日期
  int dayOfWeek = receiveDate.dayOfWeek; // 获取星期几

  if (dayOfWeek >= 1 && dayOfWeek <= 5) {
    // 工作日
    log.info("工作日")
    recoveryTime += 24.hours
  } else {
    // 周末
    log.info("周末")
    recoveryTime += 48.hours
  }
  log.info("回收时间：" + recoveryTime)
  // 更新线索回收时间
  def (Boolean error, Map data, String errorMessage) = Fx.object.update("LeadsObj", context.data["_id"] as String, ["lead_recovery_time__c": recoveryTime], UpdateAttribute.builder().triggerWorkflow(true).build())
  if (error) {
    log.info("error:" + errorMessage)
  }
}else{
  log.info("线索未被领取")
}
